insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('sport-studies:2-4-1-etiquette-of-performers:mcq:ddf54f13', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'mcq', 'mcq', 1, '{"question": "Which of these is the clearest example of gamesmanship?", "options": ["Deliberately punching an opponent off the ball whenever the match referee happens to not be looking", "Congratulating an opponent generously after they win a hard-fought contest", "Following every written rule and every unwritten convention of the sport", "Deliberately taking the maximum time allowed between points to unsettle an opponent''s rhythm"]}'::jsonb, '{"answer": 3, "explain": "Using the full, legal time allowance purely to disrupt an opponent is gamesmanship — legal, but chasing an edge. Punching an opponent breaks a written rule, so it is cheating, not gamesmanship."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:mcq:71d34c06', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'mcq', 'mcq', 1, '{"question": "What is the key difference between gamesmanship and cheating?", "options": ["Gamesmanship always breaks a written rule, whereas cheating never breaks any rule at all", "Gamesmanship never breaks a written rule; cheating does break a written rule", "There is no real difference between gamesmanship and cheating at all", "Cheating is only possible in individual sports, never in team sports"]}'::jsonb, '{"answer": 1, "explain": "Gamesmanship always stays inside the written rulebook, even while chasing an edge. Cheating actually breaks a written rule — that is the exam-worthy distinction."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:mcq:0dc92714', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'mcq', 'mcq', 1, '{"question": "A team is known for consistently showing good etiquette and sportsmanship. What is this most likely to do for the sport?", "options": ["Guarantee the team a better result than their skill level deserves", "Remove the need for the sport to have any officials at future matches", "Help reinforce positive sporting values that the sport depends on", "Stop any other team from ever using gamesmanship tactics again"]}'::jsonb, '{"answer": 2, "explain": "Consistent good conduct reinforces values like respect and fair play — it does not guarantee results, remove the need for officials, or stop others'' behaviour."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tf:eb3eea9e', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tf', 'tf', 1, '{"question": "Etiquette is the same thing as the sport''s official written rulebook."}'::jsonb, '{"answer": false, "explain": "Etiquette is UNWRITTEN — conventions that go beyond the rulebook, not the rulebook itself."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tf:110ecb27', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tf', 'tf', 1, '{"question": "Sportsmanship means respecting the spirit of the rules, not just the letter."}'::jsonb, '{"answer": true, "explain": "Sportsmanship covers both the letter AND the spirit — playing fairly even when nobody is checking."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tf:5b585514', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tf', 'tf', 1, '{"question": "Gamesmanship involves openly breaking a written rule of the sport."}'::jsonb, '{"answer": false, "explain": "Gamesmanship always stays inside the written rules — it bends them for an edge, but never technically breaks them. Breaking a rule is cheating."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tf:2efc4ee5', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tf', 'tf', 1, '{"question": "One reason for observing etiquette is protecting the safety of fellow participants."}'::jsonb, '{"answer": true, "explain": "Safety is one of the three reasons — some conventions exist purely to stop performers being hurt."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tf:0800db85', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tf', 'tf', 1, '{"question": "A performer who has to be told every time to stay quiet is showing strong etiquette."}'::jsonb, '{"answer": false, "explain": "Recognising the moment yourself, without being told, is the real mark of good etiquette."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tf:de190ec2', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tf', 'tf', 1, '{"question": "Gamesmanship and cheating mean exactly the same thing."}'::jsonb, '{"answer": false, "explain": "Gamesmanship never breaks a written rule; cheating does. That distinction is exactly what the exam tests."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:learn:f7d844c1', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'learn', 'mcq', 1, '{"readingTitle": "Etiquette: what it is and why performers observe it", "reading": "<h4>What ''etiquette'' means in sport</h4>\n<ul>\n<li><strong>Etiquette</strong> is the unwritten code of good conduct and manners a performer is expected to follow — conventions that go beyond what is written in the sport''s official rulebook.</li>\n<li>A performer can obey every written rule of a sport and still behave badly by ignoring etiquette — for example, celebrating right in an injured opponent''s face breaks no written rule, but it is still poor conduct.</li>\n</ul>\n<h4>Why performers observe it — three reasons</h4>\n<ul>\n<li><strong>Fairness</strong> — some conventions exist purely so that no performer gains an advantage that has nothing to do with skill (for example, staying still in an opponent''s eyeline during their shot).</li>\n<li><strong>Safety of fellow participants</strong> — some conventions exist purely to stop performers being hurt (for example, not tackling once play has already stopped).</li>\n<li><strong>Reinforcing positive sporting values</strong> — following etiquette consistently keeps values such as respect and fair play alive within a sport, for everyone taking part and watching.</li>\n</ul>", "question": "Which of these best explains what ''etiquette'' means for a performer?", "options": ["An unwritten code of good conduct that goes beyond the sport''s official rulebook", "Every written law and regulation that is printed inside the sport''s official rulebook", "A list of skills a performer must master before being allowed to compete at all", "The scoring system used by officials to work out the final result of a match"]}'::jsonb, '{"answer": 0, "explain": "Etiquette is unwritten — conventions beyond the rulebook. Option B describes the opposite (written rules), and the others describe skill requirements or scoring, not etiquette."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:learn:ecddd31d', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'learn', 'mcq', 1, '{"readingTitle": "Knowing when to be quiet or hold back", "reading": "<h4>Recognising the right moment</h4>\n<ul>\n<li>Good etiquette often means a performer recognising a moment when staying quiet, still or out of the way is the appropriate thing to do — without needing to be told.</li>\n<li>Examples across sports: staying silent while an opponent lines up a decisive shot; not walking across the field of play while the ball is live; waiting for a rally to finish before returning a stray ball.</li>\n</ul>\n<h4>Why this matters</h4>\n<ul>\n<li>These moments usually protect the same two reasons as above — interrupting at the wrong time can distract an opponent unfairly, or create a safety risk if performers collide.</li>\n<li>A performer who has to be reminded every single time is showing they do not really understand etiquette — recognising the moment yourself is the mark of a well-mannered competitor.</li>\n</ul>", "question": "A performer notices their opponent is about to take a shot that will decide the point. What does good etiquette suggest?", "options": ["Call out something distracting at exactly the moment your opponent is about to strike the ball", "Stay completely still and silent until the shot has been taken", "Walk across the playing area to fetch a different ball while play continues", "Ask the referee to pause the whole match until you are ready to keep watching"]}'::jsonb, '{"answer": 1, "explain": "Etiquette means holding back at the decisive moment. Calling out, walking across live play, or demanding a pause would all distract or disrupt — the opposite of what is expected."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:learn:01d83883', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'learn', 'mcq', 1, '{"readingTitle": "Sportsmanship: the letter AND the spirit of the rules", "reading": "<h4>The definition to learn</h4>\n<ul>\n<li><strong>Sportsmanship</strong> means playing within the letter of the rules (the written laws) <strong>and</strong> the spirit of the rules (the fairness those laws are trying to protect) — even when nobody is checking.</li>\n<li>A sportsmanlike performer would rather lose fairly than win by exploiting a loophole nobody has noticed.</li>\n</ul>\n<h4>An example</h4>\n<ul>\n<li>In a school football match, a striker notices the ball went out of play just before they scored, but the assistant referee has not seen it. The striker tells the referee the ball was out, giving up the goal, because winning that way would not feel like a genuine win.</li>\n</ul>", "question": "Which of these best matches the definition of sportsmanship used in this course?", "options": ["Playing strictly within the written rules while still quietly hunting for any legal edge available", "Refusing to compete against any opponent who is clearly stronger than you are", "Playing within the letter and the spirit of the rules, even when no official is checking", "Following only the instructions given personally by your coach or team manager"]}'::jsonb, '{"answer": 2, "explain": "Sportsmanship covers BOTH the letter and the spirit of the rules, unchecked. Option A describes gamesmanship instead — legal, but chasing an edge rather than respecting fairness."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:learn:e5c7a5a6', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'learn', 'mcq', 1, '{"readingTitle": "Gamesmanship: bending the rules for an edge", "reading": "<h4>The definition to learn</h4>\n<ul>\n<li><strong>Gamesmanship</strong> means bending the rules, or using legal-but-borderline tactics, to gain an advantage — <strong>without technically breaking any written rule</strong>.</li>\n<li>The key difference from cheating: gamesmanship never breaks a written law of the sport. The key difference from sportsmanship: it ignores the spirit of fair competition to chase an edge.</li>\n</ul>\n<h4>Examples</h4>\n<ul>\n<li>A tennis player takes the maximum time allowed between points, every single point, once they start losing momentum — purely to disrupt their opponent''s rhythm.</li>\n<li>A losing team''s substitute takes slightly longer than necessary to leave the pitch in the closing minutes, running down the clock.</li>\n</ul>\n<h4>Sportsmanship vs gamesmanship — the core contrast</h4>\n<ul>\n<li>Sportsmanship respects the spirit of the rules; gamesmanship exploits the letter of the rules while ignoring their spirit.</li>\n<li>Both stay inside the written rulebook — the difference is intention: fairness versus advantage-seeking.</li>\n</ul>", "question": "Which of these is the best description of gamesmanship?", "options": ["Deliberately and openly breaking a written rule of the sport in order to win", "Following both the written rules and their underlying spirit at every moment", "Refusing to take part in any competition unless the playing conditions are absolutely perfect in every way", "Bending the rules or seeking a legal-but-unfair edge, without technically breaking a written rule"]}'::jsonb, '{"answer": 3, "explain": "Gamesmanship stays legal but chases an edge. Option A describes cheating (a rule IS broken), and option B describes sportsmanship instead."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:misc:71d34c06', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Gamesmanship is basically just another word for cheating, since both are about trying to win unfairly.</p><p><strong>✅ The correct idea:</strong> They are different ideas the exam tests precisely. GAMESMANSHIP stays inside the written rules while chasing a legal-but-unfair edge. CHEATING actually breaks a written rule. A player time-wasting legally is gamesmanship; a player throwing a punch off the ball breaks a rule and is cheating.</p>", "question": "What is the key difference between gamesmanship and cheating?", "options": ["Cheating always avoids breaking any written rule, while gamesmanship constantly breaks the sport''s rulebook", "Gamesmanship stays inside the written rules of the sport; cheating breaks a written rule", "There is no meaningful difference between the two ideas at all", "Gamesmanship only happens in team sports, never in individual ones"]}'::jsonb, '{"answer": 1, "explain": "Gamesmanship never technically breaks a written rule; cheating does. That is the precise distinction the exam rewards."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:misc:4290f39b', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Sportsmanship just means being a good loser and shaking hands at the end.</p><p><strong>✅ The correct idea:</strong> That is only a small, final part of it. The full definition is playing within the letter AND the spirit of the rules THROUGHOUT the whole contest — not just being gracious once it is over. A player could shake hands warmly at the end and still have shown poor sportsmanship during the match itself.</p>", "question": "Which of these captures the FULL meaning of sportsmanship, not just part of it?", "options": ["Being polite to the officials only after the final whistle has been blown", "Shaking hands warmly with opponents at the end, regardless of how fairly the match itself was played", "Playing within the letter and the spirit of the rules throughout the whole contest", "Applauding your own teammates loudly whenever they happen to score a point"]}'::jsonb, '{"answer": 2, "explain": "Sportsmanship applies throughout the contest, not only at the final whistle — a warm handshake alone does not prove fair play took place during the match."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:misc:58160189', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> As long as I don''t break a written rule, it doesn''t matter how I behave — that''s just part of the game.</p><p><strong>✅ The correct idea:</strong> This ignores etiquette and the spirit of the rules, which matter even when no written rule is broken. A performer can stay entirely legal and still show poor conduct — distracting an opponent, ignoring a safety convention, or refusing to acknowledge a genuine error. Legal is not the same as well-mannered.</p>", "question": "A performer says ''I never break a written rule, so how I behave doesn''t matter.'' What is missing from this view?", "options": ["It ignores etiquette and the spirit of the rules, which matter even when no written rule is broken", "It ignores the fact that written rules are only ever a small part of everything a referee is actually watching for", "It ignores the exact scoreline of the match at the moment the behaviour happens", "It ignores how many spectators are physically present inside the stadium that day"]}'::jsonb, '{"answer": 0, "explain": "Staying legal is not the same as showing good conduct — etiquette and the spirit of fair play matter beyond just the written rulebook."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:misc:531978ff', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> ''Knowing when to be quiet'' is only about politeness — it has nothing to do with safety.</p><p><strong>✅ The correct idea:</strong> It links to BOTH reasons for etiquette, not just fairness/politeness. Holding back at the wrong moment can also risk a collision — for example, walking into a live playing area, or moving suddenly near a performer mid-action. Etiquette protects safety just as much as it protects fairness.</p>", "question": "Why can ''knowing when to be quiet or hold back'' matter for safety, not just politeness?", "options": ["Because staying quiet at the right moment always guarantees that a performer will go on to win their next contest", "Because officials are not allowed to speak until a performer has finished talking", "Because it has no connection to safety and is only a matter of good manners", "Because holding back at the wrong moment can cause a collision or distract someone dangerously"]}'::jsonb, '{"answer": 3, "explain": "Interrupting or moving at the wrong moment risks a collision as well as unfair distraction — etiquette serves safety, not just politeness."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tips:ec007d76', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Etiquette questions range from quick recall to a full 8-mark discussion. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"State one reason for observing etiquette [1]\" = write the reason, nothing more.</li>\n<li><strong>Explain</strong> — give a reason, using the word <em>because</em>. \"Explain why a tactic is gamesmanship\" = say what it is, plus why it counts, linked to the scenario.</li>\n<li><strong>Discuss</strong> (the Section C 8-marker) — weigh up both sides (the short-term appeal of gamesmanship AND the longer-term cost) and reach a justified judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [4] in Section B wants two developed, applied points; [8] wants balance plus a judgement.</p>", "question": "A question says: ''Identify one reason why performers observe etiquette [1]''. What is the safest answer?", "options": ["A full paragraph explaining fairness, safety and reinforcing values all together", "One named reason, such as fairness or safety", "A list of every user group who might take part in the sport", "A description of the referee''s full matchday routine and duties"]}'::jsonb, '{"answer": 1, "explain": "''Identify'' + [1] = one named reason. A full paragraph, a list of user groups, or a description of duties all waste time on a single-mark question."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tips:6e24c3c2', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tips', 'mcq', 1, '{"readingTitle": "tip — The core contrast: never blur sportsmanship and gamesmanship", "reading": "<p>The single most common way to lose marks here is defining gamesmanship as cheating, or sportsmanship as only \"being a good loser\". Always state BOTH halves of the real definition:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Gamesmanship is cheating.\"</li>\n<li><strong>✅ full marks:</strong> \"Gamesmanship bends the rules for an advantage without technically breaking them, whereas sportsmanship respects the spirit of the rules even when nobody is checking.\"</li>\n</ul>\n<p>In <strong>Section B</strong> you will usually be given a scenario. Decide first whether the behaviour described breaks a written rule (cheating), stays legal but chases an edge (gamesmanship), or respects fairness throughout (sportsmanship) — then explain using detail from the scenario.</p>", "question": "Which answer about gamesmanship is most likely to earn full marks?", "options": ["Gamesmanship means cheating by openly and deliberately breaking a written rule of the sport itself", "Gamesmanship is exactly the same idea as good sportsmanship in every sport", "Gamesmanship bends the rules for an advantage, without technically breaking any of them", "Gamesmanship only exists in sports that do not use a professional referee"]}'::jsonb, '{"answer": 2, "explain": "Full marks needs the precise definition: bending the rules for an edge WITHOUT breaking them. Calling it cheating, or the same as sportsmanship, misses the exam-worthy distinction."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:tips:9b83b0a7', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where etiquette appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> etiquette appears as quick recall in <strong>Section A</strong> (identify/state a reason or definition), as an applied point in <strong>Section B</strong> scenarios (deciding whether behaviour is sportsmanship or gamesmanship), and it feeds <strong>Section C</strong> 8-mark answers about the impact of relying on gamesmanship rather than sportsmanship.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always give BOTH halves of the sportsmanship/gamesmanship definitions — never just half.</li>\n<li>In a scenario, check first: does it break a written rule (cheating), stay legal but chase an edge (gamesmanship), or respect fairness throughout (sportsmanship)?</li>\n<li>For an 8-mark Discuss, weigh gamesmanship''s small short-term gain against its longer-term cost to reputation and trust.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One example of gamesmanship here is… because…\"</li>\n<li>\"This differs from sportsmanship because…\"</li>\n<li>\"Overall, the greater impact is… because…\"</li>\n</ul>", "question": "Why is naming a specific example the strongest way to answer a Section B question here?", "options": ["Because the marks reward applying the idea to the given scenario, not a general definition", "Because writing a specific example always takes far less time to plan than a full definition does", "Because officials only accept answers that contain a specific example", "Because a definition on its own is never accepted by any exam board"]}'::jsonb, '{"answer": 0, "explain": "Section B is applied — the marks are for using the scenario in front of you, not just stating a general definition."}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:fib:8c910cef', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'fib', 'fib', 1, '{"question": "Etiquette is an _____ code of good conduct that goes beyond a sport''s official rulebook.", "blankOptions": {"B1": ["safety", "spirit", "unwritten", "technically"]}}'::jsonb, '{"blanks": {"B1": "unwritten"}}'::jsonb),
