('sport-studies:2-4-1-etiquette-of-performers:match:8abdbf67', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Etiquette”?", "options": ["A reason for good conduct: stopping an advantage that has nothing to do with a performer''s actual skill", "The unwritten code of good conduct expected of a performer, beyond the sport''s official rulebook", "A common example of legally using up the clock to protect a lead near the end of a contest", "Playing within both the written rules and their underlying spirit, even when no one is checking"]}'::jsonb, '{"answer": 1, "explain": "“Etiquette” means: The unwritten code of good conduct expected of a performer, beyond the sport''s official rulebook"}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:match:ad96c1af', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sportsmanship”?", "options": ["Playing within both the written rules and their underlying spirit, even when no one is checking", "Bending the rules or chasing a borderline advantage, without technically breaking any written law", "A reason for good conduct: protecting others from being hurt during a contest", "A common example of legally using up the clock to protect a lead near the end of a contest"]}'::jsonb, '{"answer": 0, "explain": "“Sportsmanship” means: Playing within both the written rules and their underlying spirit, even when no one is checking"}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:match:6333f8b5', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Gamesmanship”?", "options": ["A reason for good conduct: keeping ideas like respect and fair play alive within a sport", "Playing within both the written rules and their underlying spirit, even when no one is checking", "A reason for good conduct: protecting others from being hurt during a contest", "Bending the rules or chasing a borderline advantage, without technically breaking any written law"]}'::jsonb, '{"answer": 3, "explain": "“Gamesmanship” means: Bending the rules or chasing a borderline advantage, without technically breaking any written law"}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:match:7240bec1', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fairness”?", "options": ["Bending the rules or chasing a borderline advantage, without technically breaking any written law", "A reason for good conduct: keeping ideas like respect and fair play alive within a sport", "A reason for good conduct: protecting others from being hurt during a contest", "A reason for good conduct: stopping an advantage that has nothing to do with a performer''s actual skill"]}'::jsonb, '{"answer": 3, "explain": "“Fairness” means: A reason for good conduct: stopping an advantage that has nothing to do with a performer''s actual skill"}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:match:74733892', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Safety of fellow participants”?", "options": ["A reason for good conduct: keeping ideas like respect and fair play alive within a sport", "Playing within both the written rules and their underlying spirit, even when no one is checking", "Bending the rules or chasing a borderline advantage, without technically breaking any written law", "A reason for good conduct: protecting others from being hurt during a contest"]}'::jsonb, '{"answer": 3, "explain": "“Safety of fellow participants” means: A reason for good conduct: protecting others from being hurt during a contest"}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:match:22d27fd7', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Reinforcing positive sporting values”?", "options": ["A reason for good conduct: keeping ideas like respect and fair play alive within a sport", "A reason for good conduct: protecting others from being hurt during a contest", "Bending the rules or chasing a borderline advantage, without technically breaking any written law", "The unwritten code of good conduct expected of a performer, beyond the sport''s official rulebook"]}'::jsonb, '{"answer": 0, "explain": "“Reinforcing positive sporting values” means: A reason for good conduct: keeping ideas like respect and fair play alive within a sport"}'::jsonb),
('sport-studies:2-4-1-etiquette-of-performers:match:c3cc10ae', 'sport-studies', 'sport-studies:2-4-1-etiquette-of-performers', '2.4.1 Etiquette of Performers', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Time-wasting”?", "options": ["A common example of legally using up the clock to protect a lead near the end of a contest", "Playing within both the written rules and their underlying spirit, even when no one is checking", "A reason for good conduct: stopping an advantage that has nothing to do with a performer''s actual skill", "A reason for good conduct: protecting others from being hurt during a contest"]}'::jsonb, '{"answer": 0, "explain": "“Time-wasting” means: A common example of legally using up the clock to protect a lead near the end of a contest"}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:exam:9f681e84', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these best shows a spectator meeting their responsibility to the people sitting around them?", "options": ["Standing up in front of other spectators and blocking their view of the pitch whenever it suits you", "Being considerate of other spectators, for example not pushing through the crowd", "Taking whichever seat looks best regardless of the ticket you actually bought", "Talking as loudly as possible for the entire duration of the fixture"], "hint": "Think about who is being protected — the people around you in the crowd.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: B — Being considerate of other spectators, for example not pushing through the crowd.</strong></p>\n<ul>\n<li>This directly protects other spectators'' enjoyment and safety.</li>\n<li>The other options describe behaviour that disregards the people around you.</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:mcq:73201477', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'mcq', 'mcq', 1, '{"question": "Why do spectators stay quiet during a tennis serve or a golf putt?", "options": ["Because sudden noise at that moment could distract the performer and affect a fair outcome", "Because officials can issue a fine to any spectator heard whispering during a changeover", "Because the venue''s insurance policy legally requires total silence throughout the whole match", "Because performers are physically unable to continue if any sound at all is heard nearby"]}'::jsonb, '{"answer": 0, "explain": "Quiet at key moments protects concentration and fairness. It has nothing to do with fines, insurance rules, or an inability to continue."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:mcq:70d7cba8', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'mcq', 'mcq', 1, '{"question": "A spectator shouts loudly just as a sprinter is about to start a race, on purpose. This spectator has...", "options": ["shown good etiquette by creating an exciting atmosphere for the crowd around them", "broken etiquette, because they have deliberately tried to distract a performer", "followed the correct procedure for encouraging a nervous competitor before a big race", "committed an action that automatically disqualifies the sprinter from the whole competition"]}'::jsonb, '{"answer": 1, "explain": "Deliberately distracting a performer at a crucial moment breaks etiquette — it is not exciting atmosphere, correct procedure, or grounds to disqualify the sprinter."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:mcq:d1eae6a0', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'mcq', 'mcq', 1, '{"question": "A supporter disagrees with a refereeing decision. Which reaction best fits spectator etiquette?", "options": ["Shouting personal abuse at the referee until the decision is reversed", "Showing disagreement without abusing or threatening the official", "Invading the pitch to confront the referee face to face immediately", "Refusing to accept any decision the referee makes for the rest of the fixture, however small"]}'::jsonb, '{"answer": 1, "explain": "Disagreeing is normal; abuse, invading the pitch, and refusing to accept every future decision are all etiquette breaches, not acceptable reactions."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:mcq:a479e2f5', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'mcq', 'mcq', 1, '{"question": "Which shows good spectator etiquette towards the people sitting around you?", "options": ["Standing up and blocking other people''s view whenever you personally feel like it", "Being considerate of other spectators, for example not pushing through the crowd", "Taking the best seat available regardless of the ticket you originally bought", "Talking as loudly as possible throughout the whole event so everyone can hear you"]}'::jsonb, '{"answer": 1, "explain": "Consideration for fellow spectators — not pushing through crowds — is the etiquette point. Blocking views, seat-taking, and constant loud talking all disregard others."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:mcq:d8f89ec0', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'mcq', 'mcq', 1, '{"question": "A spectator throws an object onto the pitch during play. This is a problem mainly because...", "options": ["it could injure a player, official or another spectator nearby", "the referee is required to award a penalty to the away team automatically", "the match ball becomes too heavy to kick accurately for the rest of the game", "every spectator in that stand must be moved to a completely different seat"]}'::jsonb, '{"answer": 0, "explain": "Throwing objects is primarily a safety risk to people nearby — it does not change the ball''s weight, trigger an automatic penalty, or force a mass reseating."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:mcq:8cc7ee08', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'mcq', 'mcq', 1, '{"question": "Which statement about spectator behaviour is most accurate?", "options": ["Spectators should stay completely silent for the full duration of every single fixture", "Spectators can cheer and applaud, but should be quiet at specific key moments", "Spectators are never allowed to make any noise once a competition has begun", "Spectators should always cheer as loudly as possible no matter what is happening"]}'::jsonb, '{"answer": 1, "explain": "Cheering and applause are normal; only specific key moments (like a serve or a putt) call for quiet — total silence and constant loud cheering are both wrong."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tf:771bc90a', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tf', 'tf', 1, '{"question": "Spectators should stay quiet during a tennis serve or a golf putt."}'::jsonb, '{"answer": true, "explain": "Noise at that exact moment could unfairly distract the performer, so quiet at these key moments protects a fair contest."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tf:0db5ffb0', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tf', 'tf', 1, '{"question": "Cheering and applause are never acceptable at any point during a sporting fixture."}'::jsonb, '{"answer": false, "explain": "Cheering and applause are normal and welcome between points or after a good shot — only specific key moments call for quiet."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tf:d962c02a', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tf', 'tf', 1, '{"question": "Disagreeing with a referee''s decision is against spectator etiquette."}'::jsonb, '{"answer": false, "explain": "Disagreeing is normal. What breaks etiquette is HOW you disagree — abusing or threatening the official is the actual problem."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tf:91cecb85', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tf', 'tf', 1, '{"question": "A spectator who blocks another spectator''s view is showing poor etiquette."}'::jsonb, '{"answer": true, "explain": "Spectators have a responsibility to be considerate of fellow spectators, including not blocking their view."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tf:b6c32dc3', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tf', 'tf', 1, '{"question": "Throwing an object onto the pitch during play is a safety issue as well as an etiquette issue."}'::jsonb, '{"answer": true, "explain": "It could injure a player, official or another spectator, so it breaks both safety rules and spectator etiquette."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tf:08aa94c6', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tf', 'tf', 1, '{"question": "Spectator etiquette only concerns how you treat the players, not other people in the crowd."}'::jsonb, '{"answer": false, "explain": "It also concerns responsibility to fellow spectators — not blocking views or spoiling their enjoyment — not just the players."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:learn:4b8bdc21', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'learn', 'mcq', 1, '{"readingTitle": "What ''spectator etiquette'' means", "reading": "<h4>The idea</h4>\n<ul>\n<li><strong>Etiquette</strong> is the accepted, respectful way of behaving in a situation. For spectators, it means the accepted way to behave while <strong>watching</strong> a sport — not while playing it.</li>\n<li>This is a different topic from performer etiquette (fairness and sportsmanship on the pitch). Here the exam question is always: <strong>how should someone in the crowd behave?</strong></li>\n</ul>\n<h4>Why it matters</h4>\n<ul>\n<li>Sport only works as a spectacle if the crowd lets it happen properly — a performer who cannot concentrate, or a spectator whose enjoyment is ruined by others, both lose out.</li>\n<li>Good spectator etiquette protects three things at once: the <strong>performers''</strong> ability to compete fairly, <strong>other spectators''</strong> enjoyment, and everyone''s <strong>safety</strong>.</li>\n</ul>", "question": "Spectator etiquette is best described as...", "options": ["the accepted way of behaving in the crowd while watching sport", "a set of tactical rules that only professional performers are trained to follow before a competition", "the official rulebook a referee uses to award points during a match", "a list of penalties for players who commit deliberate fouls during play"]}'::jsonb, '{"answer": 0, "explain": "Etiquette for spectators is about how the crowd behaves while watching — not a tactical rulebook for performers, an officials'' scoring system, or a list of foul penalties."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:learn:e2ca4d32', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'learn', 'mcq', 1, '{"readingTitle": "Appropriate behaviour when watching", "reading": "<h4>Quiet at the right moments</h4>\n<ul>\n<li>Some sports need silence at a precise moment because noise can break a performer''s concentration and affect a fair outcome. Classic examples: staying <strong>quiet during a tennis serve</strong>, and staying <strong>quiet while a golfer is putting</strong>.</li>\n<li>This is not the same as staying silent for the whole match — cheering and applause are expected and welcome between points, at the end of a rally, or after a good shot.</li>\n</ul>\n<h4>Not distracting or abusing players and officials</h4>\n<ul>\n<li>Spectators must not deliberately put a performer off — for example shouting during a run-up, waving objects, or using banned lights or flashes near the field of play.</li>\n<li>Etiquette also rules out <strong>abusing</strong> players or officials: no verbal abuse, threats, or aggressive criticism of a decision. Disagreeing with a decision is normal; abusing someone for it is not.</li>\n</ul>", "question": "Which of these is an example of appropriate spectator behaviour?", "options": ["Staying quiet while a golfer lines up and takes a crucial putt", "Shouting loudly at the exact moment a tennis player begins their serve to put them off", "Screaming personal abuse at the referee every time a decision goes against your team", "Standing up and waving a large flag directly in a sprinter''s line of sight as the race starts"]}'::jsonb, '{"answer": 0, "explain": "Staying quiet at a genuinely crucial moment protects a fair contest. Deliberately distracting a server, abusing an official, or blocking a sprinter''s sightline are all etiquette breaches."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:learn:f2f43ed2', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'learn', 'mcq', 1, '{"readingTitle": "Responsibility to others — and to safety", "reading": "<h4>Two audiences to respect</h4>\n<ul>\n<li>A spectator has a responsibility to <strong>fellow spectators</strong> — not blocking their view, not pushing through a crowd, and not spoiling their enjoyment with disruptive or aggressive behaviour.</li>\n<li>A spectator also has a responsibility to <strong>the players</strong> — not intimidating them, not invading their space, and reacting to decisions in a way that does not threaten anyone.</li>\n</ul>\n<h4>Safety — not endangering others</h4>\n<ul>\n<li>Etiquette includes basic safety: never throwing objects onto a pitch, court or course; never invading the playing area; not crowding walkways or blocking an exit.</li>\n<li>A strong exam answer names the <strong>group affected</strong> (fellow spectators, players, or both) and the specific <strong>behaviour or risk</strong> — not just \"be safe\" or \"be nice\".</li>\n</ul>", "question": "A question asks you to explain a spectator''s responsibility to OTHER spectators. Which answer fits best?", "options": ["Not blocking another spectator''s view or pushing through the crowd", "Staying completely silent for the entire duration of the fixture from start to finish", "Buying the most expensive ticket available for the stand", "Arriving before the players so you get the best seat in the ground"]}'::jsonb, '{"answer": 0, "explain": "Responsibility to fellow spectators is about consideration — not blocking views or pushing through crowds — not about silence, ticket price, or arrival time."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:misc:cbdae608', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Etiquette for spectators just means being quiet all the time.</p><p><strong>✅ The correct idea:</strong> Etiquette means being quiet at specific key moments (like a serve or a putt), but cheering and applause are expected and welcome at other times. Confusing ''quiet at the right moment'' with ''silent the whole match'' misdescribes the behaviour and loses marks.</p>", "question": "What does spectator etiquette actually say about noise during a fixture?", "options": ["Stay quiet at specific key moments, but cheering and applause elsewhere are normal", "Make no sound whatsoever from the very first whistle to the very last whistle of the game", "Only match officials are permitted to make any noise inside the stadium at any point", "Cheer as loudly as possible without any pause for the entire length of the fixture"]}'::jsonb, '{"answer": 0, "explain": "It is quiet at KEY moments, not total silence — the other options describe rules that do not exist."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:misc:e0ae2094', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Disagreeing with a referee''s decision breaks spectator etiquette.</p><p><strong>✅ The correct idea:</strong> Disagreement itself is normal and expected — supporters will not always agree with a decision. What breaks etiquette is HOW you disagree: abuse, threats or invading the pitch. The exam rewards naming the specific behaviour (abuse/threats), not just ''disagreeing''.</p>", "question": "What actually breaks spectator etiquette when you disagree with a referee''s decision?", "options": ["Abusing or threatening the official, rather than simply disagreeing with the decision", "Sitting in complete silence and refusing to react to the decision at all for the rest of the match", "Politely applauding every single decision the referee makes throughout the whole game", "Discussing the decision quietly with the people sitting in the seats around you"]}'::jsonb, '{"answer": 0, "explain": "Disagreement is normal; abuse or threats are what break etiquette, not silence, applause, or a quiet discussion with neighbours."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:misc:34a2cd34', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Spectator etiquette is only about how you treat the players.</p><p><strong>✅ The correct idea:</strong> It covers responsibility to fellow spectators too — not blocking views, not pushing through crowds, not spoiling others'' enjoyment — as well as responsibility to the players and safety for everyone.</p>", "question": "Spectator etiquette covers responsibility towards...", "options": ["both fellow spectators and the players, not just one of these groups", "only the performers taking part, with no responsibility owed to anyone else in the crowd at all", "only the match officials, since spectators cannot affect anyone else at a fixture", "nobody in particular, because spectators are not covered by any etiquette rules"]}'::jsonb, '{"answer": 0, "explain": "It covers BOTH fellow spectators and players — restricting it to only performers, only officials, or nobody misses half the topic."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:misc:52fe38b1', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Etiquette for performers and for spectators is the same thing, so a spectator question can be answered with performer points.</p><p><strong>✅ The correct idea:</strong> They are different topics on the exam. Performer etiquette (2.4.1) is about how competitors behave when they play — fairness and sportsmanship. Spectator etiquette (this topic) is about how the crowd behaves while watching. A question naming ''spectators'' needs spectator-specific points (quiet moments, responsibility to others, safety), not performer points like gamesmanship.</p>", "question": "A question specifically asks about SPECTATOR etiquette. What should you avoid writing about?", "options": ["Points that are really about performer behaviour, such as gamesmanship on the pitch", "The specific quiet moments and examples of appropriate crowd behaviour that this exact topic wants you to give", "A spectator''s responsibility to the people sitting around them in the crowd", "Basic safety points about not throwing objects onto the playing area"]}'::jsonb, '{"answer": 0, "explain": "Performer points like gamesmanship belong to a different topic (2.4.1) — a spectator question needs spectator-specific points, not performer ones."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tips:380470a3', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Spectator-etiquette questions are usually short. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name it. \"Identify one example of appropriate spectator behaviour [1]\" = one named example, nothing more.</li>\n<li><strong>Describe</strong> — say what the behaviour looks like in a bit more detail.</li>\n<li><strong>Explain</strong> — give a reason. Use the word <em>because</em>. \"Explain why spectators should be quiet during a golf putt\" = the behaviour <em>plus</em> why it matters.</li>\n<li><strong>Discuss</strong> — used for the big 8-mark answers; balance points and reach a judgement.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; short Section A items usually want one point per mark; Section C''s 8 marks want a balanced, judged discussion.</p>", "question": "A question says: ''Identify one example of appropriate spectator behaviour [1]''. What is the safest answer?", "options": ["One clear example, such as staying quiet during a serve", "A full paragraph explaining several different examples in a lot of detail", "A long list of every single example you can possibly think of", "An example of performer behaviour instead of spectator behaviour"]}'::jsonb, '{"answer": 0, "explain": "''Identify'' + [1] wants one named example. A paragraph, a long list, or the wrong topic (performers) all waste the mark."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tips:8c5f211f', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: behaviour → who it affects → why", "reading": "<p>The single most common way to lose marks here is naming a behaviour with nothing else. Build every answer as <strong>behaviour → who it affects → why it matters</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Being quiet.\"</li>\n<li><strong>✅ full marks:</strong> \"Spectators should be quiet during a golf putt, because noise at that moment could distract the golfer and affect a fair outcome.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named venue, named incidents). Then you must use a detail <em>from that scenario</em>, not a general example.</p>", "question": "Which answer about spectator behaviour is most likely to earn full marks?", "options": ["Naming the behaviour, who it affects, and why it matters", "Just naming a behaviour with no further detail at all", "Listing as many different behaviours as you can remember", "Describing your own personal opinion of a professional athlete"]}'::jsonb, '{"answer": 0, "explain": "Full marks come from behaviour + who it affects + why — a bare name, a long list, or a personal opinion do not show that understanding."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:tips:e8528c54', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> spectator etiquette appears as quick recall in <strong>Section A</strong> (identify/state), as applied points in <strong>Section B</strong> scenarios about specific incidents, and it feeds <strong>Section C</strong> 8-mark answers discussing behaviour across a whole sport.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Always separate \"quiet at key moments\" from \"silent the whole match\" — the exam rewards precision, not blanket rules.</li>\n<li>Name WHO is affected (a performer, fellow spectators, or both) — it shows you understand responsibility, not just rules.</li>\n<li>Remember safety is its own point, distinct from noise or abuse — don''t forget objects, pitch invasions and crowding.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One way spectator behaviour affects this sport is… because…\"</li>\n<li>\"This matters because…\"</li>\n<li>\"However, the extent to which this matters depends on…\"</li>\n</ul>", "question": "Why is ''safety'' a useful point to add to a longer spectator-etiquette answer?", "options": ["It shows you understand a spectator''s responsibility beyond just noise", "It simply fills space in the answer without needing to explain anything else properly", "It means spectator behaviour has no effect on anyone else nearby", "It replaces the need to mention performers or officials at all"]}'::jsonb, '{"answer": 0, "explain": "Safety is a distinct, creditable point showing wider understanding — it is not filler, and it doesn''t remove the need for other points."}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:fib:e93eb9e9', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'fib', 'fib', 1, '{"question": "Spectator etiquette is the accepted, respectful way of _____ while watching a sport.", "blankOptions": {"B1": ["quiet", "behaving", "abusing", "injure"]}}'::jsonb, '{"blanks": {"B1": "behaving"}}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:fib:c06cbb47', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'fib', 'fib', 1, '{"question": "Spectators should stay _____ during a tennis serve or a golf putt, because noise could distract the performer.", "blankOptions": {"B1": ["abusing", "behaving", "injure", "quiet"]}}'::jsonb, '{"blanks": {"B1": "quiet"}}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:fib:fe4ec797', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'fib', 'fib', 1, '{"question": "Disagreeing with an official''s decision is normal, but _____ them is not.", "blankOptions": {"B1": ["fellow", "quiet", "abusing", "injure"]}}'::jsonb, '{"blanks": {"B1": "abusing"}}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:fib:8117aee3', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'fib', 'fib', 1, '{"question": "A good spectator is considerate towards _____ spectators as well as the players.", "blankOptions": {"B1": ["fellow", "injure", "abusing", "behaving"]}}'::jsonb, '{"blanks": {"B1": "fellow"}}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:fib:a94f54e8', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'fib', 'fib', 1, '{"question": "Throwing objects onto the playing area can _____ a player, official or another spectator.", "blankOptions": {"B1": ["abusing", "injure", "quiet", "behaving"]}}'::jsonb, '{"blanks": {"B1": "injure"}}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:match:bc1fc35b', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Spectator etiquette”?", "options": ["Times such as a tennis serve or a golf putt when noise could unfairly affect the outcome", "Verbal abuse or threats aimed at a referee or umpire over a decision", "The accepted, respectful way of behaving while watching sport", "Not throwing objects, invading the playing area, or endangering anyone nearby"]}'::jsonb, '{"answer": 2, "explain": "“Spectator etiquette” means: The accepted, respectful way of behaving while watching sport"}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:match:c6c61d32', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Quiet moments”?", "options": ["Times such as a tennis serve or a golf putt when noise could unfairly affect the outcome", "The accepted, respectful way of behaving while watching sport", "Deliberately shouting, waving or flashing lights to put a competitor off", "Behaving in a way that does not spoil other people''s enjoyment or safety"]}'::jsonb, '{"answer": 0, "explain": "“Quiet moments” means: Times such as a tennis serve or a golf putt when noise could unfairly affect the outcome"}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:match:d5ec6b1d', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Distracting a performer”?", "options": ["Not throwing objects, invading the playing area, or endangering anyone nearby", "Deliberately shouting, waving or flashing lights to put a competitor off", "Times such as a tennis serve or a golf putt when noise could unfairly affect the outcome", "Verbal abuse or threats aimed at a referee or umpire over a decision"]}'::jsonb, '{"answer": 1, "explain": "“Distracting a performer” means: Deliberately shouting, waving or flashing lights to put a competitor off"}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:match:322a5ec8', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Abusing an official”?", "options": ["Times such as a tennis serve or a golf putt when noise could unfairly affect the outcome", "Verbal abuse or threats aimed at a referee or umpire over a decision", "The accepted, respectful way of behaving while watching sport", "Deliberately shouting, waving or flashing lights to put a competitor off"]}'::jsonb, '{"answer": 1, "explain": "“Abusing an official” means: Verbal abuse or threats aimed at a referee or umpire over a decision"}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:match:56339635', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Responsibility to fellow spectators”?", "options": ["The accepted, respectful way of behaving while watching sport", "Times such as a tennis serve or a golf putt when noise could unfairly affect the outcome", "Behaving in a way that does not spoil other people''s enjoyment or safety", "Deliberately shouting, waving or flashing lights to put a competitor off"]}'::jsonb, '{"answer": 2, "explain": "“Responsibility to fellow spectators” means: Behaving in a way that does not spoil other people''s enjoyment or safety"}'::jsonb),
('sport-studies:2-4-2-etiquette-of-spectators:match:b63d112f', 'sport-studies', 'sport-studies:2-4-2-etiquette-of-spectators', '2.4.2 Etiquette of Spectators', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Safety at a venue”?", "options": ["Not throwing objects, invading the playing area, or endangering anyone nearby", "Deliberately shouting, waving or flashing lights to put a competitor off", "Behaving in a way that does not spoil other people''s enjoyment or safety", "Verbal abuse or threats aimed at a referee or umpire over a decision"]}'::jsonb, '{"answer": 0, "explain": "“Safety at a venue” means: Not throwing objects, invading the playing area, or endangering anyone nearby"}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:exam:2f2f010b', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'exam', 'mcq', 1, '{"num": "2", "question": "Which of these is a genuine reason some sports performers give for using a PED?", "options": ["Their national governing body has officially approved its use for every athlete", "It is freely available from any high-street supermarket without restriction", "They believe it will help them recover faster from an injury and train harder", "A referee has personally recommended it before an important fixture"], "hint": "Think about which option matches a reason actually taught on this page.", "starter": "The correct answer is..."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark (AO2)</h5>\n<p><strong>Answer: C — They believe it will help them recover faster from an injury and train harder.</strong></p>\n<ul>\n<li>Faster recovery and harder training is one of the recognised reasons performers give.</li>\n<li>The other options describe things that are not true of a banned PED (official approval, free availability, referee recommendation).</li>\n</ul>\n</div>", "modelAnswer": ""}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:mcq:19cc6950', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'mcq', 'mcq', 1, '{"question": "A performer takes a banned substance so their body performs better than training alone could. What is this substance called?", "options": ["A performance-enhancing drug (PED)", "A licensed supplement approved for use by the athlete''s national governing body", "A recovery drink that is sold openly in any supermarket or high-street pharmacy", "A type of monitoring equipment used to record an athlete''s heart rate in training"]}'::jsonb, '{"answer": 0, "explain": "This is the definition of a PED. A governing-body-approved supplement, a supermarket drink and monitoring equipment are all legal and are not PEDs."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:mcq:a0dff060', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'mcq', 'mcq', 1, '{"question": "Which of these best shows ''pressure to win or succeed'' as a reason for using a PED?", "options": ["A performer enjoys watching highlights of other athletes competing at major international events", "A performer feels that only finishing first can justify the sacrifices they have already made", "A performer prefers early morning training sessions rather than joining a full squad session", "A performer changes clubs because the new club happens to train closer to their family home"]}'::jsonb, '{"answer": 1, "explain": "Feeling that only winning justifies years of sacrifice is pressure to succeed. Enjoying highlights, a training-time preference and changing clubs for convenience are not this pressure."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:mcq:36b2bcef', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'mcq', 'mcq', 1, '{"question": "How can fame and sponsorship push a performer towards using a PED?", "options": ["Sponsors often ask performers to wear a particular brand of training shoe", "Being well known makes it slightly easier to book a table at a busy restaurant", "Media appearances usually take place on the morning after a big competition", "Losing form could cost them their sponsorship income and their public profile"]}'::jsonb, '{"answer": 3, "explain": "The risk of losing income and profile is the real pressure. Wearing sponsored kit, restaurant bookings and appearance timing are unrelated details, not pressures to dope."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:mcq:5b00e2dc', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'mcq', 'mcq', 1, '{"question": "A performer suspects several rivals are secretly using banned substances. Why might this push them towards doping too?", "options": ["They plan to publicly accuse those rivals of doping at the next major press conference they attend", "They feel doping is the only way left to compete on what feels like equal terms", "They decide to switch permanently to a completely different sporting event entirely", "They ask their coach to file a formal complaint with the event organisers instead"]}'::jsonb, '{"answer": 1, "explain": "Believing rivals already dope can make a performer feel they must do the same to keep up — even though that belief doesn''t make doping fair or legal."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:mcq:bcff64e1', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'mcq', 'mcq', 1, '{"question": "A performer is racing to recover from injury before a major competition. Which reason for using a PED does this describe?", "options": ["Wanting a PED purely because a teammate has recommended trying it out first", "Wanting a PED purely so they can skip the qualifying rounds required before the next major competition", "Wanting a PED to speed up recovery and allow much harder training in the meantime", "Wanting a PED to change which weight category they are allowed to compete in"]}'::jsonb, '{"answer": 2, "explain": "Speeding up recovery from injury and enabling harder training is the reason described. Skipping qualifiers, changing categories and peer suggestion are different issues."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:mcq:7c5328c0', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'mcq', 'mcq', 1, '{"question": "Which of these describes a physical, rather than psychological, gain some PEDs are used for?", "options": ["A reduced feeling of anxiety before stepping out in front of a large home crowd", "Increased confidence during the final, most pressured stage of a long and closely fought competition", "A dulled awareness of pain and fatigue while competing near the end of a race", "Extra strength, speed or endurance that can turn a good performance into a winning one"]}'::jsonb, '{"answer": 3, "explain": "Strength, speed and endurance are physical gains. Reduced anxiety, increased confidence and dulled pain awareness are all psychological (mental) effects, not physical ones."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tf:eaa59226', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tf', 'tf', 1, '{"question": "A PED is defined as a banned substance that boosts performance beyond what training alone could achieve."}'::jsonb, '{"answer": true, "explain": "That is the definition — being BANNED and giving an artificial edge is what makes a substance a PED, not simply that it affects performance."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tf:63350c65', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tf', 'tf', 1, '{"question": "A legal vitamin tablet or protein shake counts as a PED."}'::jsonb, '{"answer": false, "explain": "Legal supplements are not banned, so they are not PEDs — even though they may support training and recovery."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tf:62e3ea4c', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tf', 'tf', 1, '{"question": "Performers only ever dope for one single reason at a time."}'::jsonb, '{"answer": false, "explain": "Reasons usually combine — competitive pressure, money, injury recovery and psychological effects can all be present together."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tf:fb408b44', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tf', 'tf', 1, '{"question": "Believing that rivals are already doping makes it fair and legal for a performer to dope too."}'::jsonb, '{"answer": false, "explain": "That belief is a reason performers GIVE — it never actually makes doping fair or legal, even if the belief is genuinely held."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tf:ae1900d2', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tf', 'tf', 1, '{"question": "PEDs can only ever affect the body, never the mind."}'::jsonb, '{"answer": false, "explain": "Some PEDs also produce psychological effects, such as reduced anxiety or increased confidence, alongside any physical change."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tf:83a655de', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tf', 'tf', 1, '{"question": "Wanting to recover more quickly from an injury before a major competition can be a reason for using a PED."}'::jsonb, '{"answer": true, "explain": "Faster recovery from injury (and the chance to return to harder training sooner) is one of the recognised reasons performers give."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:learn:c92742ef', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'learn', 'mcq', 1, '{"readingTitle": "What is a PED, and why do performers use one?", "reading": "<h4>Defining a PED</h4>\n<ul>\n<li>A <strong>performance-enhancing drug (PED)</strong> is a banned substance that a performer takes to make their body perform better than training, diet and natural ability alone could achieve.</li>\n<li>A PED is not the same as a legal supplement. A vitamin tablet or a protein shake is allowed; what makes something a PED is that it is <strong>banned</strong> because it gives an artificial edge other performers do not have.</li>\n</ul>\n<h4>Why \"why\" matters</h4>\n<ul>\n<li>This page looks only at the <strong>reasons performers give for using PEDs</strong> — not whether those reasons are acceptable. The health, ethical, legal and career case AGAINST using PEDs is covered on a separate page.</li>\n<li>Very few performers dope for a single reason. Usually several pressures — competitive, financial, physical and psychological — build up together.</li>\n</ul>", "question": "Which of these best describes what makes a substance a PED?", "options": ["A drink or snack an athlete happens to have shortly before any competition", "A banned substance used to make the body perform better than training alone could", "A legal vitamin supplement that all professional athletes are encouraged to take daily", "A specialist training programme only available to full-time professional athletes"]}'::jsonb, '{"answer": 1, "explain": "A PED is defined by being BANNED and giving an artificial edge — legal supplements, pre-match snacks and training programmes are not PEDs."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:learn:313e1e5f', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Winning, money and the fear that rivals are already doping", "reading": "<h4>Pressure to win and succeed</h4>\n<ul>\n<li>Top-level sport can feel like it only rewards first place. Some performers feel intense <strong>pressure to win or succeed</strong> — from themselves, a coach, a country, or years of sacrifice — and see a PED as a shortcut to that success.</li>\n<li>The closer a performer gets to elite level, the smaller the gaps between rivals become, so even a small artificial advantage can feel decisive.</li>\n</ul>\n<h4>Financial reward, fame and sponsorship</h4>\n<ul>\n<li>Winning at the highest level can bring <strong>financial rewards</strong>, media <strong>fame</strong>, and valuable <strong>sponsorship deals</strong>. For some performers, their income and career depend on staying near the top.</li>\n<li>A performer worried about losing funding, a team place, or a sponsor''s support may see doping as protecting their livelihood, not only their pride.</li>\n</ul>\n<h4>\"Everyone else is doing it\"</h4>\n<ul>\n<li>Some performers use PEDs because they <strong>believe their rivals are already doping</strong>. They convince themselves that using one too is the only way to compete on equal terms — even though that belief may be wrong, and it never actually makes doping fair or legal.</li>\n</ul>", "question": "Why might a performer''s belief about their rivals lead them to use a PED?", "options": ["An official has personally confirmed that doping is now permitted at every level", "They simply want to copy a rival''s kit sponsor because they like the new design", "They believe rivals are already doping, so they feel they must too to keep up", "Their national governing body offers a cash reward for reporting a rival who cheats"]}'::jsonb, '{"answer": 2, "explain": "The belief that rivals are already doping — right or wrong — is a genuine reason some performers give, distinct from an official ruling or a kit preference."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:learn:fee99197', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'learn', 'mcq', 1, '{"readingTitle": "Training harder, recovering faster — and the physical and mental pull", "reading": "<h4>Training harder and recovering faster</h4>\n<ul>\n<li>Some PEDs let a performer <strong>train harder and for longer</strong> than their body would naturally allow, and <strong>recover more quickly</strong> from intense training or from an injury.</li>\n<li>A performer under pressure to return from injury quickly — for example before a major competition — may see a PED as a way to speed that recovery up.</li>\n</ul>\n<h4>Physical gains</h4>\n<ul>\n<li>PEDs can produce real physical changes: extra <strong>strength</strong>, extra <strong>speed</strong>, or greater <strong>endurance</strong> — often exactly the gains that separate a good performance from a winning one.</li>\n</ul>\n<h4>Psychological effects</h4>\n<ul>\n<li>Some PEDs affect the mind as well as the body — for example reducing anxiety, raising confidence, or dulling the perception of pain and fatigue during competition. A performer may use a PED partly for this mental lift, not only for a physical gain.</li>\n</ul>", "question": "Which of these is a PSYCHOLOGICAL reason a performer might give for using a PED, rather than a purely physical one?", "options": ["It can noticeably increase a performer''s muscle size and top running speed", "It can make a performer feel calmer, more confident or less aware of pain", "It can shorten the time a performer needs to recover from a hard session", "It can be bought at a lower price than most legal supplements in a shop"]}'::jsonb, '{"answer": 1, "explain": "Feeling calmer or more confident is a mental (psychological) effect. Muscle size, speed and recovery time are physical effects, and price is unrelated to either."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:misc:675870f2', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Doping is always just about wanting to win — there''s no other reason involved.</p><p><strong>✅ The correct idea:</strong> Winning is a common reason, but it is rarely the only one. Financial pressure (sponsorship and income), the belief that rivals already dope, faster injury recovery, and psychological effects like reduced anxiety can all combine with the wish to win. A strong answer names more than one pressure, not just ''winning''.</p>", "question": "Which statement best reflects why performers actually give for using PEDs?", "options": ["Winning is genuinely and completely the only reason any performer would ever consider", "Performers only ever dope because a coach personally orders it", "Several different pressures can combine, not just the wish to win", "There is no real pattern to why any performer chooses to dope"]}'::jsonb, '{"answer": 2, "explain": "The reasons stack up together — competitive, financial, physical and psychological — so ''just winning'' undersells the topic and loses marks."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:misc:3647062f', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> If a performer believes their rivals are doping, that belief makes it fair for them to dope too.</p><p><strong>✅ The correct idea:</strong> This is a REASON some performers give, not a justification. Believing rivals are already using PEDs does not make doping legal or fair — it is still banned and still against the rules, whatever a performer privately believes about their competition.</p>", "question": "A performer says: ''Everyone else is doing it, so it''s fine if I do it too.'' What is the accurate view of this?", "options": ["It is a genuine reason some performers give, but it does not make doping fair or legal", "It is completely correct, because doping only becomes banned once a majority stop using it", "It means the performer will automatically be cleared if they are later tested", "It proves that every single one of their rivals must already be using a PED"]}'::jsonb, '{"answer": 0, "explain": "The belief explains WHY a performer might dope, but explaining a reason is not the same as the reason making the act fair or legal."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:misc:2ee35460', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> PEDs only ever change how strong, fast or fit a performer''s body is.</p><p><strong>✅ The correct idea:</strong> PEDs can also change how a performer FEELS. Alongside physical gains like strength, speed or endurance, some PEDs reduce anxiety, raise confidence, or dull the sense of pain and fatigue — a psychological effect as well as a physical one.</p>", "question": "What is missing from the claim that PEDs ''only ever affect the body''?", "options": ["It ignores the price that a performer would have to pay to obtain a PED", "It ignores possible psychological effects, such as reduced anxiety or greater confidence", "It ignores the fact that PEDs are always completely undetectable in every single drug test", "It ignores the length of ban an athlete would receive if they were caught"]}'::jsonb, '{"answer": 1, "explain": "Physical change is only half the picture — psychological effects (calmer, more confident, less aware of pain) are part of why some performers use PEDs."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tips:15e3a620', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Command words for this topic — what each one wants", "reading": "<p>Questions on why performers use PEDs are usually short recall or short application. Match your answer length to the command word:</p>\n<ul>\n<li><strong>Identify / State</strong> — just name the reason. \"State one reason a performer might use a PED [1]\" = one named reason, nothing more.</li>\n<li><strong>Describe</strong> — say what the reason involves. \"Describe one reason...\" = give the features of that pressure.</li>\n<li><strong>Explain</strong> — add why it pushes a performer towards doping. Use the word <em>because</em> and link the reason to the effect it has on the performer.</li>\n</ul>\n<p><strong>Read the mark tariff:</strong> [1] wants one point; [2] usually wants two named reasons, or one point developed; [4] in Section B wants reasons applied to the scenario you are given.</p>", "question": "A question says: ''Identify two reasons why a performer might use a PED [2]''. What is the safest answer?", "options": ["Two named reasons, nothing more", "One long paragraph exploring a single reason in depth", "A full page listing every reason you can possibly remember", "A description of a famous doping case you once read about"]}'::jsonb, '{"answer": 0, "explain": "''Identify'' + [2] = two names, one mark each. A long paragraph on one reason, or a long list, wastes time without earning extra marks."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tips:39a5f681', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — The golden rule: name the reason AND link it to the performer", "reading": "<p>The most common way to lose marks here is stopping at a bare label. Build every answer as <strong>reason → link to the performer</strong>:</p>\n<ul>\n<li><strong>❌ 0–1 marks:</strong> \"Sponsorship.\"</li>\n<li><strong>✅ full marks:</strong> \"A performer might use a PED because losing form could cost them their sponsorship income, which they may depend on for their career.\"</li>\n</ul>\n<p>In <strong>Section B</strong> the question gives you a scenario (a named performer, a named pressure). You must then use a detail <em>from that scenario</em>, not a generic example.</p>", "question": "In a Section B scenario about a named performer under pressure, your explanation should come from...", "options": ["any doping story you happen to already know", "your own opinion about whether doping should be legal", "the scenario you are given", "a completely different sport to the one in the scenario"]}'::jsonb, '{"answer": 2, "explain": "Section B is applied — the marks are for using the scenario in front of you. A generic reason that ignores the scenario is capped."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:tips:7d68871d', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'tips', 'mcq', 1, '{"readingTitle": "tip — Where this topic appears + sentence starters", "reading": "<p><strong>Where it shows up:</strong> reasons for using PEDs appear as quick recall in <strong>Section A</strong> (identify/state/explain), as applied points in a <strong>Section B</strong> scenario about a named performer, and can feed a <strong>Section C</strong> 8-mark Discuss question about doping more broadly.</p>\n<p><strong>Three punchy tips:</strong></p>\n<ul>\n<li>Learn the reasons in groups (competitive, financial, physical, psychological) so you can always recall several.</li>\n<li>For every reason, memorise <em>one</em> way it links to the performer — that link is usually where the mark is.</li>\n<li>Remember that reasons combine — a strong answer rarely relies on just one pressure.</li>\n</ul>\n<p><strong>Sentence starters for a longer answer:</strong></p>\n<ul>\n<li>\"One reason performers may use PEDs is… because…\"</li>\n<li>\"This pressure matters because…\"</li>\n<li>\"However, this reason does not make doping…\"</li>\n</ul>", "question": "Why is it useful to remember that reasons for doping usually combine, rather than acting alone?", "options": ["It means only one single reason is ever tested in the exam", "It proves that doping should be made completely legal for everyone", "It replaces the need to give any reason at all in your answer", "It shows deeper understanding than naming just one pressure"]}'::jsonb, '{"answer": 3, "explain": "Showing that pressures stack up (competitive, financial, physical, psychological) demonstrates the depth of understanding a Section B or C answer rewards."}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:fib:8e83cf5e', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'fib', 'fib', 1, '{"question": "A PED is a _____ substance taken to make the body perform better than training alone could.", "blankOptions": {"B1": ["terms", "sponsorship", "banned", "psychological"]}}'::jsonb, '{"blanks": {"B1": "banned"}}'::jsonb),
