('sport-studies:2-5-1-why-performers-use-peds:fib:31f98860', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'fib', 'fib', 1, '{"question": "Losing form could cost a performer their income and their _____ deals.", "blankOptions": {"B1": ["banned", "sponsorship", "succeed", "terms"]}}'::jsonb, '{"blanks": {"B1": "sponsorship"}}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:fib:202f5b45', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'fib', 'fib', 1, '{"question": "Believing that rivals are already doping can make a performer feel they must too, to compete on equal _____.", "blankOptions": {"B1": ["terms", "sponsorship", "banned", "succeed"]}}'::jsonb, '{"blanks": {"B1": "terms"}}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:fib:1540573f', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'fib', 'fib', 1, '{"question": "Some PEDs can dull the perception of pain, which is a _____ rather than physical effect.", "blankOptions": {"B1": ["succeed", "psychological", "terms", "banned"]}}'::jsonb, '{"blanks": {"B1": "psychological"}}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:match:ba61b8c1', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Performance-enhancing drug (PED)”?", "options": ["Wanting to return to full training sooner than the body would naturally allow", "A banned substance taken to make the body perform better than training alone could", "Fear of losing income and profile if form or results start to slip", "A PED changing how a performer feels, such as calmer or more confident"]}'::jsonb, '{"answer": 1, "explain": "“Performance-enhancing drug (PED)” means: A banned substance taken to make the body perform better than training alone could"}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:match:d991d7ad', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Pressure to win or succeed”?", "options": ["Wanting to return to full training sooner than the body would naturally allow", "Fear of losing income and profile if form or results start to slip", "Feeling that only finishing first justifies the sacrifice already made", "Thinking a PED is the only way left to compete on equal terms"]}'::jsonb, '{"answer": 2, "explain": "“Pressure to win or succeed” means: Feeling that only finishing first justifies the sacrifice already made"}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:match:acd91477', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Sponsorship pressure”?", "options": ["Fear of losing income and profile if form or results start to slip", "Feeling that only finishing first justifies the sacrifice already made", "Wanting to return to full training sooner than the body would naturally allow", "A PED changing how a performer feels, such as calmer or more confident"]}'::jsonb, '{"answer": 0, "explain": "“Sponsorship pressure” means: Fear of losing income and profile if form or results start to slip"}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:match:6a2a632d', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Belief rivals are already doping”?", "options": ["Thinking a PED is the only way left to compete on equal terms", "Feeling that only finishing first justifies the sacrifice already made", "A banned substance taken to make the body perform better than training alone could", "A PED changing how a performer feels, such as calmer or more confident"]}'::jsonb, '{"answer": 0, "explain": "“Belief rivals are already doping” means: Thinking a PED is the only way left to compete on equal terms"}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:match:3839dd25', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Faster recovery from injury”?", "options": ["Feeling that only finishing first justifies the sacrifice already made", "A PED changing how a performer feels, such as calmer or more confident", "Wanting to return to full training sooner than the body would naturally allow", "Thinking a PED is the only way left to compete on equal terms"]}'::jsonb, '{"answer": 2, "explain": "“Faster recovery from injury” means: Wanting to return to full training sooner than the body would naturally allow"}'::jsonb),
('sport-studies:2-5-1-why-performers-use-peds:match:a37df435', 'sport-studies', 'sport-studies:2-5-1-why-performers-use-peds', '2.5.1 Why Performers Use PEDs', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Psychological effect”?", "options": ["A PED changing how a performer feels, such as calmer or more confident", "A banned substance taken to make the body perform better than training alone could", "Feeling that only finishing first justifies the sacrifice already made", "Wanting to return to full training sooner than the body would naturally allow"]}'::jsonb, '{"answer": 0, "explain": "“Psychological effect” means: A PED changing how a performer feels, such as calmer or more confident"}'::jsonb)
